"use client";

import { useMemo, useState } from "react";
import Link from "next/link";
import { ChevronDown, Mail, Phone } from "lucide-react";
import PageHero from "@/components/PageHero";
import SectionReveal from "@/components/SectionReveal";
import { SITE } from "@/lib/constants";
import styles from "./page.module.css";

type Category = "All" | "About the Service" | "Booking" | "Vehicles & Equipment" | "Billing" | "Coverage";

const FAQ_ITEMS = [
  { category: "About the Service", question: "What is non-emergency patient transport?", answer: "Non-emergency patient transport is scheduled medical transportation for people who need mobility support but do not require an emergency ambulance response." },
  { category: "About the Service", question: "Who typically uses Norfolk Patient Transport?", answer: "Patients using medical appointments, hospital discharges, dialysis treatment, care home transfers, and other planned healthcare-related travel commonly use the service." },
  { category: "About the Service", question: "Can a family member or escort ride along?", answer: "Often yes. Escort availability depends on the vehicle setup, the patient’s mobility needs, and how much support is required during the trip." },
  { category: "Booking", question: "How far in advance should I book?", answer: "When possible, book 24 to 48 hours in advance. Same-day requests may still be available depending on dispatch capacity and route availability." },
  { category: "Booking", question: "What information do you need when I book?", answer: "Have the patient’s name, mobility type, pickup and destination details, preferred date and time, contact information, and any special handling notes ready." },
  { category: "Booking", question: "How does the booking confirmation process work?", answer: "After a request is submitted, dispatch reviews the trip details, confirms the transport setup, and follows up with the booking contact to finalize the ride." },
  { category: "Vehicles & Equipment", question: "Do you provide wheelchair transport?", answer: "Yes. We support wheelchair-accessible transport with securement systems and mobility-aware loading and unloading." },
  { category: "Vehicles & Equipment", question: "Do you provide stretcher transport?", answer: "Yes. Stretcher-capable trips are available for patients who cannot safely remain upright during transport." },
  { category: "Vehicles & Equipment", question: "Can you accommodate oxygen or higher-support trips?", answer: "Trip requirements are reviewed by dispatch in advance so the appropriate vehicle and staffing arrangement can be assigned when possible." },
  { category: "Billing", question: "What payment methods are accepted?", answer: "Private-pay bookings can request common methods such as credit card, cash, or e-transfer. Approved facilities may qualify for invoice-based billing." },
  { category: "Billing", question: "Do hospitals and facilities get Net 30 billing?", answer: "Approved hospitals, clinics, retirement residences, and care facilities may qualify for Net 30 billing and account-based booking workflows." },
  { category: "Coverage", question: "What areas do you serve?", answer: "Coverage includes Norfolk County, Haldimand County, Simcoe, Port Dover, Delhi, Brantford, Hamilton, Hagersville, Tillsonburg, and surrounding areas." },
  { category: "Coverage", question: "What if I am not sure whether my destination is covered?", answer: "Call dispatch directly. If the route fits operational coverage, the team will confirm pickup timing and transport suitability." },
] as const;

const categories: Category[] = ["All", "About the Service", "Booking", "Vehicles & Equipment", "Billing", "Coverage"];

export default function FAQPage() {
  const [category, setCategory] = useState<Category>("All");
  const items = useMemo(
    () => (category === "All" ? FAQ_ITEMS : FAQ_ITEMS.filter((item) => item.category === category)),
    [category]
  );

  const jsonLd = {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    mainEntity: FAQ_ITEMS.map((item) => ({
      "@type": "Question",
      name: item.question,
      acceptedAnswer: {
        "@type": "Answer",
        text: item.answer,
      },
    })),
  };

  return (
    <>
      <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }} />
      <PageHero
        title="Frequently Asked Questions"
        subtitle="Everything you need to know about non-emergency patient transport."
        breadcrumb="FAQ"
      />

      <section className="section section-soft">
        <div className={`container ${styles.layout}`}>
          <SectionReveal>
            <div className={styles.filters}>
              {categories.map((item) => (
                <button
                  key={item}
                  type="button"
                  className={styles.filter}
                  data-active={category === item}
                  onClick={() => setCategory(item)}
                >
                  {item}
                </button>
              ))}
            </div>

            <div className={styles.accordion}>
              {items.map((item, index) => (
                <SectionReveal key={item.question} delay={index * 35}>
                  <details className={styles.item}>
                    <summary>
                      <span>{item.question}</span>
                      <ChevronDown size={18} />
                    </summary>
                    <p>{item.answer}</p>
                  </details>
                </SectionReveal>
              ))}
            </div>
          </SectionReveal>

          <SectionReveal className={`card ${styles.sideCard}`} delay={80}>
            <h3>Still need help?</h3>
            <p>Contact dispatch for immediate support with booking, scheduling, or facility coordination.</p>
            <div className={styles.sideActions}>
              <a href={`tel:${SITE.phoneHref}`} className="btn btn-primary btn-pill">
                <Phone size={16} /> {SITE.phoneDisplay}
              </a>
              <Link href="/contact" className="btn btn-outline btn-pill">
                <Mail size={16} /> Contact Form
              </Link>
            </div>
          </SectionReveal>
        </div>
      </section>
    </>
  );
}